<template>
  <div>
    <div class="card card-body p-4 m-3" v-if="displayQuestion">
        <p class="card-title text-muted"> {{question.topic}}</p>
        <p class="text-center h3" id="timeDisplay"> Time: 0</p>
        <component :is="question.type" v-bind:question="question" v-bind:disabled="disableQuestion" @hook:mounted="startTimer()" v-on:submit="submit"/>

        <button class="btn btn-primary" @click="submit()"> Submit </button>

        <div class="card p-3 m-1" v-if="messages.submittionReply">
            <p class="text-center h4"> {{messages.submittionReply}} </p>
        </div>
    </div>
  </div>
</template>

<script>
import MultipleChoice from './questions/MultipleChoice.vue'
import Cryptography from './questions/Cryptography.vue'
import ServerTalker from '../ServerTalker'
export default {
    name: 'Question',
    props: {
        userID: String,
        prop: String,
    },
    data() {
        return {
            question: {
                title: '',
                type: '',
                topic: '',
            },
            questionID: '',

            messages: {
                loadQuestion: '',
                submittionReply: '',
            },

            displayQuestion: false,
        }
    },
    components: {
        MultipleChoice,
        Cryptography,
    },
    async created() {
        this.questionID = this.prop
        try {
        this.question = await ServerTalker.loadQuestion(this.questionID, this.userID)
        this.displayQuestion = true
        this.disableQuestion = false
        this.messages.loadQuestion = ''
        this.messages.submittionReply = ''
        this.question.solution = {
          time: 0,
        }
      } catch(err) {
        this.messages.loadQuestion = "Error: " + err.message
      }
    },
    methods: {
        async submit() {
            try {
                this.question['reply'] = await ServerTalker.submitSolution(this.question.solution, this.question._id, this.userID)
                if (!this.question.reply.continue) {
                this.disableQuestion = true
                this.displayQuestion = false

                setTimeout(() => {
                    this.displayQuestion = true
                }, 10)
                }
                this.messages.submittionReply = this.question.reply.message
            } catch(err) {
                this.messages.submittionReply = err.message
            }
        },

        startTimer() {
            this.timeDisplay = document.getElementById('timeDisplay')

            // console.log(this.question.solution.time)
            if (this.question.solution.time > 0) {
                const ms = this.question.solution.time % 10
                const s = Math.floor(this.question.solution.time / 10 % 60)
                const m = Math.floor(this.question.solution.time / 600)
                console.log(ms, s, m)
                if (m > 0)
                this.timeDisplay.innerHTML = `Time: ${m}:${s}.${ms}`
                else
                this.timeDisplay.innerHTML = `Time: ${s}.${ms}`
            }
            
            
            clearInterval(this.timer)
            if (!this.question.reply) {
                this.timer = setInterval(() => {
                    this.question.solution.time += 1
                    const ms = this.question.solution.time % 10
                    const s = Math.floor(this.question.solution.time / 10 % 60)
                    const m = Math.floor(this.question.solution.time / 600)
                    if (m > 0)
                    this.timeDisplay.innerHTML = `Time: ${m}:${s}.${ms}`
                    else
                    this.timeDisplay.innerHTML = `Time: ${s}.${ms}`
                }, 99)
            }
        },
    }
}
</script>

