import axios from 'axios'

const url = 'https://' + window.location.host + '/api/'

class ServerTalker {
    static async loadFeed(event, topicsNames, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/loadFeed" , {
                event,
                topicsNames,
                userID
            })
            .then((res) => {
                if (res.data.status && res.data.question) {
                    const question = res.data.question;
                    resolve(question)
                } else {
                    reject(res.data)
                    console.log(res.data)
                }
            })
            .catch((err)=> {
                reject(err);
            })
            
        });
    }

    static async loadQuestion(questionID, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/loadQuestion" , {
                questionID,
                userID
            })
            .then((res) => {
                if (res.data.status && res.data.question) {
                    const question = res.data.question;
                    resolve(question)
                } else {
                    reject(res.data)
                    console.log(res.data)
                }
            })
            .catch((err)=> {
                reject(err);
            })
            
        });
    }

    static async loadLibrary(event, topicsNames, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/loadLibrary", {
                event,
                topicsNames,
                userID
            })
                .then((res) => {
                    if (res.data.status && res.data.questions) {
                        const questions = res.data.questions;
                        resolve(questions)
                    } else {
                        reject(res.data)
                    }
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

    static async submitSolution(solution, questionID, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/submitSolution", {
                solution, 
                questionID,
                userID
            })
                .then((res) => {
                    if (res.data.status) {
                        const reply = {
                            ...res.data,
                        }
                        resolve(reply)
                    } else {
                        reject("Unresolved server error")
                    }
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

    static async mockSubmitSolution(question, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/mockSubmitSolution", {
                ...question,
                userID: userID
            })
                .then((res) => {
                    if (res.data.status) {
                        const reply = {
                            ...res.data,
                        }
                        resolve(reply)
                    } else {
                        reject("Unresolved server error")
                    }
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

    static async addQuestion(question, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/addQuestion", {
                question,
                userID
            })
            .then((res) => {
                if (res.data.status) {
                    resolve(res.data)
                } else {
                    reject("Unresolved server error")
                }
            })
            .catch((err)=> {
                reject(err);
            })
        })
    }


    static async getEvents() {
        return new Promise ((resolve,reject) => {
            axios.get(url + "question/getEvents")
                .then((res) => {
                    const events = res.data.events;
                    resolve(events)
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

}

